#include <bits/stdc++.h>
using namespace std;
int a[4][4],vis[4][4];
int ans;
bool check() {
	for(int i=1; i<=3; i++) {
		if(vis[i][1]==max({vis[i][1],vis[i][2],vis[i][3]})&&a[i][2]==a[i][3]) return 0;
		if(vis[i][2]==max({vis[i][1],vis[i][2],vis[i][3]})&&a[i][1]==a[i][3]) return 0;
		if(vis[i][3]==max({vis[i][1],vis[i][2],vis[i][3]})&&a[i][2]==a[i][1]) return 0;
	}
	for(int i=1; i<=3; i++) {
		if(vis[1][i]==max({vis[1][i],vis[2][i],vis[3][i]})&&a[2][i]==a[3][i]) return 0;
		if(vis[2][i]==max({vis[1][i],vis[2][i],vis[3][i]})&&a[1][i]==a[3][i]) return 0;
		if(vis[3][i]==max({vis[1][i],vis[2][i],vis[3][i]})&&a[2][i]==a[1][i]) return 0;
	}
	if(vis[1][1]==max({vis[1][1],vis[2][2],vis[3][3]})&&a[2][2]==a[3][3]) return 0;
	if(vis[2][2]==max({vis[1][1],vis[2][2],vis[3][3]})&&a[1][1]==a[3][3]) return 0;
	if(vis[3][3]==max({vis[1][1],vis[2][2],vis[3][3]})&&a[2][2]==a[1][1]) return 0;
	if(vis[1][3]==max({vis[1][3],vis[2][2],vis[3][1]})&&a[2][2]==a[3][1]) return 0;
	if(vis[2][2]==max({vis[1][3],vis[2][2],vis[3][1]})&&a[1][3]==a[3][1]) return 0;
	if(vis[3][1]==max({vis[1][3],vis[2][2],vis[3][1]})&&a[2][2]==a[1][3]) return 0;
	return 1;
}
void dfs(int k) {
	if(k>9) {
		if(check()) ans++;
		return;
	}
	for(int i=1; i<=3; i++) {
		for(int j=1; j<=3; j++) {
			if(!vis[i][j]) {
				vis[i][j]=k;
				dfs(k+1);
				vis[i][j]=0;
			}
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	for(int i=1; i<=3; i++) {
		for(int j=1; j<=3; j++) {
			cin>>a[i][j];
		}
	}
	dfs(1);
	cout<<fixed<<setprecision(30)<<double(ans*1.0)/362880;
	return 0;
}
